import React, { useEffect, useState } from "react";
import axios from "axios";
import { useParams } from "react-router-dom";

const CourseDetail = () => {
  const { id } = useParams();  // Get the course ID from the URL
  const [course, setCourse] = useState(null);

  useEffect(() => {
    axios
      .get(`http://localhost:5000/api/courses/${id}`)  // API call to fetch course details by ID
      .then((response) => {
        console.log(response.data);  // Log data to check if course details are fetched
        setCourse(response.data);
      })
      .catch((error) => {
        console.error("There was an error fetching the course details:", error);
      });
  }, [id]);

  if (!course) return <div>Loading...</div>;  // Show loading while fetching data

  return (
    <div>
      <h2>{course.title}</h2>
      <p>{course.description}</p>
      <p>Price: ${course.price}</p>
      <p>Level: {course.level}</p>
    </div>
  );
};

export default CourseDetail;
